VALUES
  ('judicial-cf446b4c-moex-00024', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '依通說見解，下列各犯罪類型中，可成立間接正犯者為何？', '["刑法第237條之重婚罪", "刑法第122條之收受賄賂罪", "刑法第230條之血親性交罪", "刑法第168條之偽證罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00025', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑法對於假釋之規定內容，下列敘述何者正確？', '["於假釋中因故意更犯罪，受逾六月有期徒刑之宣告、且未受緩刑確定者，撤銷其假釋", "符合假釋條件者，由監獄報請法院許可假釋", "無期徒刑不得假釋", "假釋撤銷後，其出獄日數仍計入刑期內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00026', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何者非屬行刑權時效停止進行之事由？', '["受刑人受拘束人身自由保安處分之執行", "受刑人執行中脫逃", "受刑人聲請再審", "受刑人心神喪失，依檢察官之指揮停止執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00027', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列情形中，何者不構成刑法第131條規定之圖利罪？', '["主管補助審核事項之公務員，明知申請人依法不符合補助資格，仍許可其補助申請", "主管公路建造與維修之公務員，明知私人土地依法非由公務機關修建，仍依地方民意代表之請託，幫忙 鋪造特定私人土地上通行道路之柏油路面", "負責查報違章建築之公務員，明知為違建而隱匿不予查報，使違建所有人繼續享受違建之使用利益", "承辦法制職務之公務員，明知未依法令之規定，請託承辦社會住宅分配職務之公務員，將特定社會住宅 分配給自己的親戚"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00028', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關妨害公務罪的敘述，下列何者錯誤？', '["本罪性質為結果犯，須使公務員執行職務確有遭到妨害之結果", "以強暴、脅迫手段對公務員非法職務行為加以反抗，不成立本罪", "駕駛動力交通工具對公務員施強暴脅迫者，構成加重妨害公務罪", "通緝犯將便衣刑警誤認為尋仇之人，而將其推倒在地反抗逮捕，不成立本罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00029', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲與 10 餘名志同道合民眾，公然聚集於某警局前抗議警察執法不當，意圖對警察施強暴脅迫，警察局長 乙為了避免抗議活動擴大，僅命令二次解散，未再警告，即命令員警強勢驅離群眾。有關甲、乙之刑事責 任，下列敘述何者正確？', '["甲之行為成立刑法第135條第1項妨害公務罪", "甲不成立刑法第149條第1項之聚眾不解散罪", "乙成立刑法第131條之公務員違法圖利罪", "乙成立刑法第151條之恐嚇公眾罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00030', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何種情況可成立刑法第150條之妨害秩序罪？', '["甲、乙、丙在公眾得出入之場所聚集，三人共同對在場之其他民眾施以強暴", "甲、乙、丙在公眾得出入之場所聚集，三人共同向在場之其他民眾宣達政治主張", "甲、乙、丙在公眾得出入之場所聚集，三人共同對在場之其他民眾施以詐術", "甲、乙、丙在公眾得出入之場所聚集，三人共同向在場之其他民眾播放嘲諷政治人物之影片"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00031', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於刑法第162條、第163條之縱放人犯罪，下列敘述何者正確？', '["依實務見解，私人於逮捕現行犯後，送交警察前，又予以釋放，不構成刑法第162條縱放人犯罪", "刑法上縱放人犯罪僅限於公務員始得加以違犯", "公務員因過失致依法逮捕拘禁之人脫逃，不構成犯罪", "縱放人犯而損壞拘禁處所者，僅另以毀損罪論處，不加重其刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00032', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲知悉乙與他人之債務糾紛，尚在民事法院訴訟中，乃隱匿該案之證據。關於甲之行為，下列何者正確？', '["不成立犯罪", "偽證罪", "湮滅證據罪", "妨害公務罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00033', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '意圖他人受刑事處分，向該管公務員誣告者，但於所誣告之案件裁判確定前自白者，依刑法第172條之規 定，應如何處斷？', '["不罰", "減輕或免除其刑", "得減輕其刑", "無特別法律效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
